// Analytics Dashboard Agent
// Aggregates data from all platforms and generates comprehensive performance insights

const analyticsConfig = {
  platforms: {
    youtube: {
      enabled: $env.YOUTUBE_ANALYTICS_ENABLED === 'true',
      apiKey: $env.YOUTUBE_API_KEY,
      channels: [
        { id: $env.DAX_TRAVELER_CHANNEL_ID, brand: 'dax_traveler' },
        { id: $env.GODS_VESSEL_CHANNEL_ID, brand: 'gods_vessel' },
        { id: $env.TIMEZONE_TRAVELERS_CHANNEL_ID, brand: 'timezone_travelers' },
        { id: $env.ANI_DAX_CHANNEL_ID, brand: 'ani_dax' }
      ]
    },
    google_analytics: {
      enabled: $env.GOOGLE_ANALYTICS_ENABLED === 'true',
      propertyId: $env.GA4_PROPERTY_ID,
      credentials: $env.GOOGLE_ANALYTICS_CREDENTIALS
    },
    social_media: {
      instagram: {
        enabled: $env.INSTAGRAM_INSIGHTS_ENABLED === 'true',
        accessToken: $env.INSTAGRAM_ACCESS_TOKEN
      },
      facebook: {
        enabled: $env.FACEBOOK_INSIGHTS_ENABLED === 'true',
        accessToken: $env.FACEBOOK_ACCESS_TOKEN,
        pageId: $env.FACEBOOK_PAGE_ID
      },
      twitter: {
        enabled: $env.TWITTER_ANALYTICS_ENABLED === 'true',
        bearerToken: $env.TWITTER_BEARER_TOKEN
      },
      tiktok: {
        enabled: $env.TIKTOK_ANALYTICS_ENABLED === 'true',
        accessToken: $env.TIKTOK_ACCESS_TOKEN
      }
    },
    email_marketing: {
      enabled: $env.EMAIL_ANALYTICS_ENABLED === 'true',
      provider: $env.EMAIL_PROVIDER || 'mailchimp',
      apiKey: $env.MAILCHIMP_API_KEY || $env.SENDGRID_API_KEY
    }
  },

  // Key Performance Indicators to track
  kpis: {
    revenue: {
      sources: ['patreon', 'shopify', 'printify', 'youtube', 'affiliates'],
      targets: {
        daily: 167, // $50k/month = ~$167/day
        weekly: 1167,
        monthly: 50000
      }
    },
    engagement: {
      metrics: ['views', 'likes', 'comments', 'shares', 'saves'],
      targets: {
        youtube_views: 10000,
        social_engagement_rate: 0.05,
        email_open_rate: 0.25
      }
    },
    growth: {
      metrics: ['subscribers', 'followers', 'email_list', 'customers'],
      targets: {
        youtube_subscribers: 1000,
        social_followers: 5000,
        email_subscribers: 2000
      }
    },
    conversion: {
      metrics: ['click_through_rate', 'conversion_rate', 'customer_lifetime_value'],
      targets: {
        affiliate_ctr: 0.03,
        ecommerce_conversion: 0.02,
        patreon_conversion: 0.01
      }
    }
  },

  // Time periods for analysis
  timePeriods: {
    realtime: '1h',
    daily: '24h',
    weekly: '7d',
    monthly: '30d',
    quarterly: '90d'
  }
};

const analysisTimestamp = new Date().toISOString();
const enabledPlatforms = [];

// Collect enabled platforms
Object.keys(analyticsConfig.platforms).forEach(platform => {
  if (platform === 'social_media') {
    Object.keys(analyticsConfig.platforms.social_media).forEach(social => {
      if (analyticsConfig.platforms.social_media[social].enabled) {
        enabledPlatforms.push(`social_${social}`);
      }
    });
  } else if (analyticsConfig.platforms[platform].enabled) {
    enabledPlatforms.push(platform);
  }
});

return {
  analyticsConfig,
  enabledPlatforms,
  analysisTimestamp,
  totalPlatforms: enabledPlatforms.length
};

// Configure platform-specific analytics collection
const analyticsData = $('Prepare Analytics Collection').first();
const currentPlatform = analyticsData.enabledPlatforms[$('Process Each Platform').itemIndex];

if (!currentPlatform) {
  return null;
}

// Platform-specific API configurations
function getYouTubeAnalyticsConfig(config) {
  return {
    platform: 'youtube',
    endpoints: config.channels.map(channel => ({
      url: `https://youtubeanalytics.googleapis.com/v2/reports`,
      params: {
        ids: `channel==${channel.id}`,
        startDate: new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString().split('T')[0],
        endDate: new Date().toISOString().split('T')[0],
        metrics: 'views,likes,comments,shares,subscribersGained,estimatedRevenue',
        dimensions: 'day',
        key: config.apiKey
      },
      brand: channel.brand
    }))
  };
}

function getGoogleAnalyticsConfig(config) {
  return {
    platform: 'google_analytics',
    endpoint: {
      url: `https://analyticsdata.googleapis.com/v1beta/properties/${config.propertyId}:runReport`,
      headers: {
        'Authorization': `Bearer ${config.credentials}`,
        'Content-Type': 'application/json'
      },
      body: {
        dateRanges: [{
          startDate: '7daysAgo',
          endDate: 'today'
        }],
        metrics: [
          { name: 'sessions' },
          { name: 'users' },
          { name: 'pageviews' },
          { name: 'bounceRate' },
          { name: 'sessionDuration' }
        ],
        dimensions: [
          { name: 'date' },
          { name: 'source' },
          { name: 'medium' }
        ]
      }
    }
  };
}

function getSocialMediaConfig(platform, config) {
  const configs = {
    social_instagram: {
      platform: 'instagram',
      endpoint: {
        url: 'https://graph.facebook.com/v18.0/me/insights',
        params: {
          metric: 'impressions,reach,profile_views,website_clicks',
          period: 'day',
          since: Math.floor((Date.now() - 7 * 24 * 60 * 60 * 1000) / 1000),
          until: Math.floor(Date.now() / 1000),
          access_token: config.accessToken
        }
      }
    },
    social_facebook: {
      platform: 'facebook',
      endpoint: {
        url: `https://graph.facebook.com/v18.0/${config.pageId}/insights`,
        params: {
          metric: 'page_impressions,page_reach,page_views,page_engaged_users',
          period: 'day',
          since: Math.floor((Date.now() - 7 * 24 * 60 * 60 * 1000) / 1000),
          until: Math.floor(Date.now() / 1000),
          access_token: config.accessToken
        }
      }
    },
    social_twitter: {
      platform: 'twitter',
      endpoint: {
        url: 'https://api.twitter.com/2/users/me/tweets',
        headers: {
          'Authorization': `Bearer ${config.bearerToken}`
        },
        params: {
          'tweet.fields': 'public_metrics,created_at',
          'max_results': 100
        }
      }
    },
    social_tiktok: {
      platform: 'tiktok',
      endpoint: {
        url: 'https://open-api.tiktok.com/research/video/query/',
        headers: {
          'Authorization': `Bearer ${config.accessToken}`,
          'Content-Type': 'application/json'
        },
        body: {
          query: {
            and: [
              {
                operation: 'IN',
                field_name: 'region_code',
                field_values: ['US', 'GB', 'CA']
              }
            ]
          },
          max_count: 100,
          cursor: 0
        }
      }
    }
  };

  return configs[platform];
}

// Get configuration for current platform
let platformConfig;
const config = analyticsData.analyticsConfig.platforms;

if (currentPlatform === 'youtube') {
  platformConfig = getYouTubeAnalyticsConfig(config.youtube);
} else if (currentPlatform === 'google_analytics') {
  platformConfig = getGoogleAnalyticsConfig(config.google_analytics);
} else if (currentPlatform.startsWith('social_')) {
  const socialPlatform = currentPlatform.replace('social_', '');
  const socialConfig = config.social_media[socialPlatform];
  platformConfig = getSocialMediaConfig(currentPlatform, socialConfig);
} else {
  return null;
}

return {
  ...platformConfig,
  analysisTimestamp: analyticsData.analysisTimestamp,
  kpis: analyticsData.analyticsConfig.kpis
};

// Fetch analytics data from configured platform
const platformConfig = $input.first();

// Handle different platform types
if (platformConfig.platform === 'youtube' && platformConfig.endpoints) {
  // YouTube has multiple channels to process
  return platformConfig.endpoints.map(endpoint => ({
    platform: 'youtube',
    brand: endpoint.brand,
    apiCall: {
      url: endpoint.url,
      params: endpoint.params,
      method: 'GET'
    }
  }));
} else if (platformConfig.endpoint) {
  // Single endpoint platforms
  return [{
    platform: platformConfig.platform,
    apiCall: {
      url: platformConfig.endpoint.url,
      params: platformConfig.endpoint.params,
      headers: platformConfig.endpoint.headers,
      body: platformConfig.endpoint.body,
      method: platformConfig.endpoint.body ? 'POST' : 'GET'
    }
  }];
}

return [];

// Process analytics data and calculate KPIs
const apiResponse = $input.first();
const apiConfig = $('Execute Each API Call').first();
const platformConfig = $('Configure Platform Analytics').first();

// Platform-specific data processing
function processYouTubeData(data, brand) {
  const rows = data.rows || [];
  if (rows.length === 0) return null;

  const totals = rows.reduce((acc, row) => {
    return {
      views: acc.views + (row[1] || 0),
      likes: acc.likes + (row[2] || 0),
      comments: acc.comments + (row[3] || 0),
      shares: acc.shares + (row[4] || 0),
      subscribers_gained: acc.subscribers_gained + (row[5] || 0),
      estimated_revenue: acc.estimated_revenue + (row[6] || 0)
    };
  }, { views: 0, likes: 0, comments: 0, shares: 0, subscribers_gained: 0, estimated_revenue: 0 });

  return {
    platform: 'youtube',
    brand,
    metrics: totals,
    engagement_rate: totals.views > 0 ? (totals.likes + totals.comments) / totals.views : 0,
    growth_rate: totals.subscribers_gained
  };
}

function processGoogleAnalyticsData(data) {
  const rows = data.rows || [];
  if (rows.length === 0) return null;

  const totals = rows.reduce((acc, row) => {
    return {
      sessions: acc.sessions + (row.metricValues[0]?.value || 0),
      users: acc.users + (row.metricValues[1]?.value || 0),
      pageviews: acc.pageviews + (row.metricValues[2]?.value || 0),
      bounce_rate: Math.max(acc.bounce_rate, row.metricValues[3]?.value || 0),
      session_duration: acc.session_duration + (row.metricValues[4]?.value || 0)
    };
  }, { sessions: 0, users: 0, pageviews: 0, bounce_rate: 0, session_duration: 0 });

  return {
    platform: 'website',
    metrics: totals,
    conversion_rate: totals.sessions > 0 ? totals.users / totals.sessions : 0,
    engagement_quality: totals.bounce_rate < 0.5 ? 'high' : 'medium'
  };
}

function processSocialMediaData(data, platform) {
  let metrics = {};

  if (platform === 'instagram' || platform === 'facebook') {
    const insights = data.data || [];
    insights.forEach(insight => {
      const values = insight.values || [];
      const total = values.reduce((sum, val) => sum + (val.value || 0), 0);
      metrics[insight.name] = total;
    });
  } else if (platform === 'twitter') {
    const tweets = data.data || [];
    metrics = tweets.reduce((acc, tweet) => {
      const publicMetrics = tweet.public_metrics || {};
      return {
        retweet_count: acc.retweet_count + (publicMetrics.retweet_count || 0),
        like_count: acc.like_count + (publicMetrics.like_count || 0),
        reply_count: acc.reply_count + (publicMetrics.reply_count || 0),
        quote_count: acc.quote_count + (publicMetrics.quote_count || 0)
      };
    }, { retweet_count: 0, like_count: 0, reply_count: 0, quote_count: 0 });
  }

  return {
    platform,
    metrics,
    engagement_rate: calculateSocialEngagementRate(metrics, platform)
  };
}

function calculateSocialEngagementRate(metrics, platform) {
  if (platform === 'instagram') {
    const impressions = metrics.impressions || 1;
    const engagements = (metrics.likes || 0) + (metrics.comments || 0) + (metrics.saves || 0);
    return engagements / impressions;
  } else if (platform === 'twitter') {
    const totalTweets = 1; // Simplified calculation
    const engagements = (metrics.like_count || 0) + (metrics.retweet_count || 0) + (metrics.reply_count || 0);
    return engagements / totalTweets;
  }
  return 0;
}

// Process data based on platform
let processedData;
const platform = apiConfig.platform;

if (platform === 'youtube') {
  processedData = processYouTubeData(apiResponse, apiConfig.brand);
} else if (platform === 'google_analytics') {
  processedData = processGoogleAnalyticsData(apiResponse);
} else if (['instagram', 'facebook', 'twitter', 'tiktok'].includes(platform)) {
  processedData = processSocialMediaData(apiResponse, platform);
} else {
  processedData = { platform, error: 'Unknown platform type' };
}

if (!processedData) {
  return { platform, error: 'No data available' };
}

// Calculate performance scores against KPIs
const kpis = platformConfig.kpis;
let performanceScore = 0;

if (processedData.metrics) {
  // Calculate performance based on platform type
  if (platform === 'youtube') {
    const viewsScore = Math.min(100, (processedData.metrics.views / kpis.engagement.targets.youtube_views) * 100);
    const engagementScore = Math.min(100, (processedData.engagement_rate / kpis.engagement.targets.social_engagement_rate) * 100);
    performanceScore = (viewsScore + engagementScore) / 2;
  } else if (platform === 'website') {
    const sessionScore = Math.min(100, (processedData.metrics.sessions / 1000) * 100);
    const conversionScore = Math.min(100, (processedData.conversion_rate / 0.02) * 100);
    performanceScore = (sessionScore + conversionScore) / 2;
  } else {
    const engagementScore = Math.min(100, (processedData.engagement_rate / kpis.engagement.targets.social_engagement_rate) * 100);
    performanceScore = engagementScore;
  }
}

return {
  ...processedData,
  performance_score: performanceScore,
  analysis_timestamp: platformConfig.analysisTimestamp,
  kpi_status: performanceScore >= 80 ? 'excellent' : performanceScore >= 60 ? 'good' : performanceScore >= 40 ? 'needs_improvement' : 'critical'
};

// Compile comprehensive analytics dashboard
const allAnalytics = $input.all().filter(item => !item.error);
const analyticsConfig = $('Prepare Analytics Collection').first();

// Aggregate metrics by platform type
const platformSummary = {};
const brandSummary = {};
let totalPerformanceScore = 0;
let validPlatforms = 0;

allAnalytics.forEach(analytics => {
  const platform = analytics.platform;
  const brand = analytics.brand || 'general';

  // Platform summary
  if (!platformSummary[platform]) {
    platformSummary[platform] = {
      metrics: {},
      performance_score: 0,
      count: 0
    };
  }

  // Brand summary
  if (!brandSummary[brand]) {
    brandSummary[brand] = {
      platforms: [],
      total_performance: 0,
      metrics: {}
    };
  }

  // Aggregate metrics
  if (analytics.metrics) {
    Object.keys(analytics.metrics).forEach(metric => {
      platformSummary[platform].metrics[metric] = 
        (platformSummary[platform].metrics[metric] || 0) + analytics.metrics[metric];
      brandSummary[brand].metrics[metric] = 
        (brandSummary[brand].metrics[metric] || 0) + analytics.metrics[metric];
    });
  }

  // Performance scores
  if (analytics.performance_score) {
    platformSummary[platform].performance_score += analytics.performance_score;
    platformSummary[platform].count += 1;

    brandSummary[brand].total_performance += analytics.performance_score;
    if (!brandSummary[brand].platforms.includes(platform)) {
      brandSummary[brand].platforms.push(platform);
    }

    totalPerformanceScore += analytics.performance_score;
    validPlatforms += 1;
  }
});

// Calculate average performance scores
Object.keys(platformSummary).forEach(platform => {
  if (platformSummary[platform].count > 0) {
    platformSummary[platform].performance_score /= platformSummary[platform].count;
  }
});

Object.keys(brandSummary).forEach(brand => {
  if (brandSummary[brand].platforms.length > 0) {
    brandSummary[brand].average_performance = 
      brandSummary[brand].total_performance / brandSummary[brand].platforms.length;
  }
});

// Overall performance metrics
const overallPerformance = validPlatforms > 0 ? totalPerformanceScore / validPlatforms : 0;

// Identify top performers and areas for improvement
const topPerformingPlatform = Object.keys(platformSummary).reduce((a, b) => 
  platformSummary[a].performance_score > platformSummary[b].performance_score ? a : b
);

const topPerformingBrand = Object.keys(brandSummary).reduce((a, b) => 
  (brandSummary[a].average_performance || 0) > (brandSummary[b].average_performance || 0) ? a : b
);

// Generate insights and recommendations
const insights = [];
const recommendations = [];

// Performance insights
if (overallPerformance >= 80) {
  insights.push('Excellent overall performance across all platforms');
} else if (overallPerformance >= 60) {
  insights.push('Good performance with room for optimization');
} else {
  insights.push('Performance needs significant improvement');
  recommendations.push('Focus on content quality and engagement strategies');
}

// Platform-specific insights
Object.keys(platformSummary).forEach(platform => {
  const score = platformSummary[platform].performance_score;
  if (score < 50) {
    recommendations.push(`Optimize ${platform} strategy - current score: ${score.toFixed(1)}%`);
  }
});

// Brand-specific insights
Object.keys(brandSummary).forEach(brand => {
  const score = brandSummary[brand].average_performance || 0;
  if (score < 50) {
    recommendations.push(`Review ${brand} brand strategy - current score: ${score.toFixed(1)}%`);
  }
});

// Revenue correlation (if available)
const revenueMetrics = allAnalytics.filter(a => a.metrics && a.metrics.estimated_revenue);
const totalEstimatedRevenue = revenueMetrics.reduce((sum, a) => sum + a.metrics.estimated_revenue, 0);

// Create dashboard summary
const dashboardSummary = {
  overview: {
    total_platforms: validPlatforms,
    overall_performance: overallPerformance,
    top_performing_platform: topPerformingPlatform,
    top_performing_brand: topPerformingBrand,
    estimated_revenue: totalEstimatedRevenue
  },
  platform_performance: platformSummary,
  brand_performance: brandSummary,
  insights,
  recommendations: recommendations.slice(0, 5), // Top 5 recommendations
  analysis_timestamp: analyticsConfig.analysisTimestamp,
  next_analysis: new Date(Date.now() + 2 * 60 * 60 * 1000).toISOString() // Next analysis in 2 hours
};

return dashboardSummary;

